module top_module (
    input clk,
    input nreset,
    input load,
    input [7:0] data,
    output [7:0] q );reg [7:0] obf_q_reg;

always @(posedge clk or negedge nreset) begin
    if (!nreset)
        obf_q_reg <= 8'b00000000;
    else if (load)
        obf_q_reg <= data;
end

assign q = obf_q_reg;

endmodule
